"""
Red-Black Tree implementation.

Properties that must hold:
1. Every node is red or black
2. Root is black
3. Every NIL leaf is black
4. Red node has only black children
5. All paths from a node to its descendant NILs have the same black count
"""

RED = True
BLACK = False


class Node:
    def __init__(self, key, color=RED, left=None, right=None, parent=None):
        self.key = key
        self.color = color
        self.left = left
        self.right = right
        self.parent = parent

    def __repr__(self):
        c = "R" if self.color == RED else "B"
        return f"Node({self.key}, {c})"


class RBTree:
    def __init__(self):
        self.NIL = Node(key=None, color=BLACK)
        self.root = self.NIL

    def _left_rotate(self, x):
        y = x.right
        x.right = y.left
        if y.left != self.NIL:
            y.left.parent = x
        y.parent = x.parent
        if x.parent is None:
            self.root = y
        elif x == x.parent.left:
            x.parent.left = y
        else:
            x.parent.right = y
        y.left = x
        x.parent = y

    def _right_rotate(self, y):
        x = y.left
        y.left = x.right
        if x.right != self.NIL:
            x.right.parent = y
        x.parent = y.parent
        if y.parent is None:
            self.root = x
        elif y == y.parent.left:
            y.parent.left = x
        else:
            y.parent.right = x
        x.right = y
        y.parent = x

